def q31_governance_path_available(repo_root: Path, rel: str) -> bool:
    pack_root = export_pack_root(repo_root, EXPORT_PACK_ID)
    packed = pack_root / q31_pack_payload_path(rel)
    if packed.exists():
        return True
    return (repo_root / rel).exists()


